                headers: {
                    "Content-Type": "application/json",
                    Authorization: `Bearer ${localStorage.getItem("adminToken") || ""}`
                },
                body: JSON.stringify(body)
            });
            alert(`Pandit ${action.toLowerCase()}ed successfully.`);
