                                        <label key={doc} className={`flex items-center gap-3 p-3 rounded-xl border cursor-pointer transition-colors ${requestedDocs.includes(doc) ? "border-amber-500 bg-amber-50 text-amber-900" : "border-slate-200 hover:bg-slate-50 text-slate-700"}`}>
                                            <input type="checkbox" checked={requestedDocs.includes(doc)} onChange={(e) => {
                                                if (e.target.checked) setRequestedDocs([...requestedDocs, doc]);
                                                else setRequestedDocs(requestedDocs.filter(d => d !== doc));
                                            }} className="w-4 h-4 text-amber-600 rounded border-slate-300 focus:ring-amber-500" />
                                            <span className="text-sm font-bold">{doc}</span>
                                        </label>
                                    ))}
                                </div>
                                <div className="flex gap-3">
                                    <button onClick={() => setModalType(null)} className="flex-1 py-3.5 rounded-xl font-bold text-slate-600 hover:bg-slate-100 transition-colors">Cancel</button>
                                    <button onClick={() => handleAction("REQUEST_INFO")} disabled={requestedDocs.length === 0} className="flex-[2] bg-amber-500 hover:bg-amber-600 disabled:opacity-50 text-white font-black py-3.5 rounded-xl transition-all active:scale-95 flex items-center justify-center gap-2">Send Request</button>
                                </div>
                            </>
                        )}

                    </div>
                </div>
            )}

        </div>
    );
}

"use client";
import React, { useEffect, useState } from "react";
import Link from "next/link";
import { formatDistanceToNow } from "date-fns";

export default function PanditVerificationQueue() {
  const [activeTab, setActiveTab] = useState("pending");
  const [search, setSearch] = useState("");
  const [pandits, setPandits] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [totalPending, setTotalPending] = useState(0);
  const [stats, setStats] = useState({ avgWaitHours: 0, oldestPendingDays: 0 });

  const fetchPandits = () => {
    setLoading(true);
    let query = `?status=${activeTab}&limit=20`;
    if (search.trim()) query += `&search=${encodeURIComponent(search)}`;

    fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001/api/v1'}/admin/pandits${query}`, {
      headers: { Authorization: `Bearer ${localStorage.getItem("adminToken") || ""}` }
    })
      .then(res => res.json())
      .then(data => {
        if (data.success) {
          setPandits(data.data);
          if (data.meta?.totalPending !== undefined) {
            setTotalPending(data.meta.totalPending);
            setStats({
              avgWaitHours: data.meta.avgWaitHours || 0,
              oldestPendingDays: data.meta.oldestPendingDays || 0
            });
          }
        }
        setLoading(false);
      })
      .catch(() => setLoading(false));
  };

  useEffect(() => {
    const timer = setTimeout(() => {
      fetchPandits();
    }, 400); // debounce search
    return () => clearTimeout(timer);
  }, [activeTab, search]);

  const tabs = [
    { id: "pending", label: "📝 Pending Review", count: activeTab === "pending" ? totalPending : undefined },
    { id: "verified", label: "✅ Verified" },
    { id: "rejected", label: "❌ Rejected" },
    { id: "all", label: "All Pandits" },
  ];

  return (
    <div className="p-8 max-w-[1400px] mx-auto space-y-6">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4 shrink-0">
        <div>
          <h1 className="text-3xl font-black tracking-tight text-slate-800 mb-2">Pandit Verification Queue</h1>
          <p className="text-slate-500 font-medium">
            <span className="font-bold text-blue-600 bg-blue-50 px-2 py-0.5 rounded-md">{totalPending} pandits</span> awaiting review
            {totalPending > 0 && activeTab === "pending" && (
              <span className="ml-2 hidden sm:inline">| Average wait: {stats.avgWaitHours} hours | Oldest pending: {stats.oldestPendingDays} days</span>
            )}
          </p>
        </div>
        <div className="relative w-full md:w-80">
          <span className="material-symbols-outlined absolute left-3 top-1/2 -translate-y-1/2 text-slate-400">search</span>
          <input
            type="text"
            placeholder="Search by name, phone or city..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full bg-white border border-slate-200 focus:border-blue-500 focus:ring-4 focus:ring-blue-50 rounded-xl pl-10 pr-4 py-2.5 font-medium transition-all"
          />
        </div>
      </div>

      <div className="flex gap-2 p-1 bg-slate-200/50 rounded-xl inline-flex w-full overflow-x-auto no-scrollbar">
        {tabs.map(t => (
          <button
            key={t.id}
            onClick={() => setActiveTab(t.id)}
            className={`whitespace-nowrap px-5 py-2.5 rounded-lg font-bold text-sm transition-all flex items-center gap-2 ${activeTab === t.id
              ? "bg-white text-slate-900 shadow-sm"
              : "text-slate-500 hover:text-slate-700 hover:bg-slate-200/50"
              }`}
          >
            {t.label}
            {t.count !== undefined && (
              <span className={`ml-1.5 px-2 py-0.5 rounded-full text-xs bg-slate-100 ${activeTab === t.id && t.count > 0 ? "bg-red-100 text-red-700" : ""}`}>
                {t.count}
              </span>
            )}
          </button>
        ))}
      </div>

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm text-slate-600">
            <thead className="bg-slate-50 text-xs uppercase font-bold text-slate-500 border-b border-slate-100">
              <tr>
                <th className="px-6 py-4">Pandit Name</th>
                <th className="px-6 py-4">City</th>
                <th className="px-6 py-4">Submitted</th>
                <th className="px-6 py-4 text-center">Documents</th>
                <th className="px-6 py-4 text-center">Video KYC</th>
                <th className="px-6 py-4">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 align-middle">
              {loading ? (
                <tr>
                  <td colSpan={6} className="px-6 py-12 text-center text-slate-400 font-medium">Loading pandits...</td>
                </tr>
              ) : pandits.length === 0 ? (
                <tr>
                  <td colSpan={6} className="px-6 py-12 text-center">
                    <div className="text-4xl mb-3">📭</div>
                    <div className="text-slate-500 font-medium">No pandits found in this queue.</div>
                  </td>
                </tr>
              ) : (
                pandits.map((p, i) => (
                  <tr key={p.id} className="hover:bg-slate-50/80 transition-colors group">
                    <td className="px-6 py-4">
                      <div className="font-bold text-slate-900">{p.user?.name}</div>
                      <div className="text-xs text-slate-400 font-medium mt-0.5 tracking-wider">
                        {p.user?.phone?.replace(/(\d{4})$/, 'XXXX')}
                      </div>
                    </td>
                    <td className="px-6 py-4 font-medium text-slate-700">{p.location || "Unknown"}</td>
                    <td className="px-6 py-4 whitespace-nowrap">
                      <span className="font-medium text-slate-600 bg-slate-100 px-3 py-1 rounded-full text-xs">
                        {formatDistanceToNow(new Date(p.updatedAt), { addSuffix: true })}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-center">
                      {p.documentUrls?.length >= 3 ? (
                        <span className="material-symbols-outlined text-green-500" title="All submitted">check_circle</span>
                      ) : p.documentUrls?.length > 0 ? (
                        <span className="material-symbols-outlined text-amber-500" title="Partial">warning</span>
                      ) : (
                        <span className="material-symbols-outlined text-slate-300" title="None">cancel</span>
                      )}
                    </td>
                    <td className="px-6 py-4 text-center">
                      {p.kycVideoUrl ? (
                        <span className="material-symbols-outlined text-green-500" title="Uploaded">verified</span>
                      ) : (
                        <span className="material-symbols-outlined text-slate-300" title="Pending">pending</span>
                      )}
                    </td>
                    <td className="px-6 py-4 pr-6">
                      <Link
                        href={`/pandits/${p.id}`}
                        className="inline-flex items-center gap-1.5 px-4 py-2 bg-white border border-slate-200 hover:border-blue-500 hover:text-blue-700 text-slate-700 font-bold rounded-lg shadow-sm w-full justify-center transition-all group-hover:bg-blue-50"
                      >
                        {activeTab === 'pending' ? 'Review' : 'View'}
                        <span className="material-symbols-outlined text-[18px]">arrow_forward</span>
                      </Link>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
}

"use client";
import React, { useState, useEffect } from "react";
import {
  Card, CardContent, CardHeader, CardTitle, CardDescription
} from "@hmarepanditji/ui/components/ui/card";
import { Button } from "@hmarepanditji/ui/components/ui/button";
import { Badge } from "@hmarepanditji/ui/components/ui/badge";
import { Input } from "@hmarepanditji/ui/components/ui/input";
import {
  Tabs, TabsList, TabsTrigger, TabsContent
} from "@hmarepanditji/ui/components/ui/tabs";
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@hmarepanditji/ui/components/ui/table";
import {
  Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter
} from "@hmarepanditji/ui/components/ui/dialog";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@hmarepanditji/ui/components/ui/select";
import { Label } from "@hmarepanditji/ui/components/ui/label";
import { Textarea } from "@hmarepanditji/ui/components/ui/textarea";

export default function PayoutsPage() {
  const [payouts, setPayouts] = useState<any[]>([]);
  const [stats, setStats] = useState<any>({});
  const [loading, setLoading] = useState(true);
  const [tab, setTab] = useState("PENDING");

  const [selectedPayout, setSelectedPayout] = useState<any | null>(null);
  const [processModalOpen, setProcessModalOpen] = useState(false);

  // Form state
  const [paymentMethod, setPaymentMethod] = useState("BANK_TRANSFER");
  const [transactionRef, setTransactionRef] = useState("");
  const [paymentDate, setPaymentDate] = useState(new Date().toISOString().split("T")[0]);
  const [notes, setNotes] = useState("");
  const [processing, setProcessing] = useState(false);

  const fetchPayouts = async () => {
    setLoading(true);
    try {
      const token = localStorage.getItem("token");
      const statusQuery = tab === "ALL" ? "" : `?status=${tab}`;
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001/api/v1'}/admin/payouts${statusQuery}`, {
        headers: {
          Authorization: `Bearer ${token}`
        }
      });
      const json = await res.json();
      if (json.success) {
        setPayouts(json.data.bookings || []);
        if (json.data.stats) setStats(json.data.stats);
      }
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchPayouts();
  }, [tab]);

  const handleProcessPayoutClick = (p: any) => {
    setSelectedPayout(p);
    setTransactionRef("");
    setNotes("");
    setPaymentMethod("BANK_TRANSFER");
    setPaymentDate(new Date().toISOString().split("T")[0]);
    setProcessModalOpen(true);
  };

  const confirmPayout = async () => {
    if (!transactionRef) return alert("Please enter a transaction reference number");
    setProcessing(true);
    try {
      const token = localStorage.getItem("token");
      const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001/api/v1'}/admin/payouts/${selectedPayout.id}/complete`, {
        method: "PATCH",
        headers: {
          "Content-Type": "application/json",
          Authorization: `Bearer ${token}`
        },
        body: JSON.stringify({
          transactionRef,
          paymentMethod,
          paymentDate,
          notes
        })
      });
      const json = await res.json();
      if (json.success) {
        alert("Payout processed successfully!");
        setProcessModalOpen(false);
        fetchPayouts();
      } else {
        alert(json.message || "Failed to process payout");
      }
    } catch (e) {
      console.error(e);
      alert("Error processing payout");
    } finally {
      setProcessing(false);
    }
  };

  const exportCSV = () => {
    const completed = payouts.filter(p => p.payoutStatus === "COMPLETED");
    const csvRows = [
      ["BookingID", "PanditName", "PanditPhone", "Amount", "BankAccount", "IFSC", "TransactionRef", "ProcessedDate"]
    ];

    completed.forEach(p => {
      csvRows.push([
        p.bookingNumber,
        p.pandit?.name || "N/A",
        p.pandit?.phone || "N/A",
        p.panditPayout.toString(),
        p.pandit?.bankDetails?.accountNumber || "N/A",
        p.pandit?.bankDetails?.ifscCode || "N/A",
        p.payoutReference || "N/A",
        p.payoutCompletedAt ? new Date(p.payoutCompletedAt).toLocaleString() : "N/A"
      ]);
    });

    const csvString = csvRows.map(row => row.join(",")).join("\n");
    const blob = new Blob([csvString], { type: "text/csv" });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = "completed_payouts.csv";
    a.click();
  };

  return (
    <div className="p-6 space-y-6 max-w-7xl mx-auto">
      <div className="flex justify-between items-center">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Payout Queue</h1>
          <p className="text-muted-foreground mt-1">Process pandit payouts after puja completion</p>
        </div>
        {tab === "COMPLETED" && (
          <Button onClick={exportCSV} variant="outline">📥 Export CSV</Button>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Pending Payouts</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats.pendingPayouts || 0}</div>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm font-medium">Total Paid (Month)</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">₹{stats.totalPayouts || 0}</div>
          </CardContent>
        </Card>
      </div>

      <Tabs value={tab} onValueChange={setTab}>
        <TabsList>
          <TabsTrigger value="PENDING">💰 Pending Payouts</TabsTrigger>
          <TabsTrigger value="COMPLETED">✅ Completed</TabsTrigger>
          <TabsTrigger value="ALL">All</TabsTrigger>
        </TabsList>

        <TabsContent value={tab} className="mt-6">
          <Card>
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Booking</TableHead>
                  <TableHead>Pandit</TableHead>
                  <TableHead>Event</TableHead>
                  <TableHead>Amount</TableHead>
                  <TableHead>Bank</TableHead>
                  {tab !== "PENDING" && <TableHead>Status</TableHead>}
                  {tab === "COMPLETED" && <TableHead>Transaction Ref</TableHead>}
                  <TableHead>Action</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {loading ? (
                  <TableRow><TableCell colSpan={8} className="text-center py-10">Loading...</TableCell></TableRow>
                ) : payouts.length === 0 ? (
                  <TableRow><TableCell colSpan={8} className="text-center py-10">No payouts found</TableCell></TableRow>
                ) : (
                  payouts.map((p) => (
                    <TableRow key={p.id}>
                      <TableCell>
                        <a href={`/bookings/${p.id}`} className="text-indigo-600 hover:underline font-medium">
                          {p.bookingNumber}
                        </a>
                      </TableCell>
                      <TableCell>
                        <div className="font-medium">{p.pandit?.name}</div>
                        <div className="text-xs text-muted-foreground">{p.pandit?.city || "Unknown City"}</div>
                      </TableCell>
                      <TableCell>
                        <div>{p.eventType}</div>
                        <div className="text-xs text-muted-foreground">
                          {new Date(p.eventDate).toLocaleDateString()}
                        </div>
                      </TableCell>
                      <TableCell className="font-bold">
                        ₹{p.panditPayout}
                        <div className="text-xs font-normal text-muted-foreground">
                          Fee: ₹{p.grandTotal - p.panditPayout}
                        </div>
                      </TableCell>
                      <TableCell>
                        <div className="text-sm">SBI — XXXX4321 {/* Masked in real data */}</div>
                      </TableCell>
                      {tab !== "PENDING" && (
                        <TableCell>
                          <Badge variant={p.payoutStatus === "COMPLETED" ? "default" : "secondary"}>
                            {p.payoutStatus}
                          </Badge>
                        </TableCell>
                      )}
                      {tab === "COMPLETED" && (
                        <TableCell>
                          <div className="text-sm font-mono">{p.payoutReference || "N/A"}</div>
                          <div className="text-xs text-muted-foreground">
                            {p.payoutCompletedAt ? new Date(p.payoutCompletedAt).toLocaleDateString() : ""}
                          </div>
                        </TableCell>
                      )}
                      <TableCell>
                        {p.payoutStatus === "PENDING" ? (
                          <Button size="sm" onClick={() => handleProcessPayoutClick(p)}>Process Payout</Button>
                        ) : (
                          <Button size="sm" variant="outline" disabled>Processed</Button>
                        )}
                      </TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          </Card>
        </TabsContent>
      </Tabs>

      <Dialog open={processModalOpen} onOpenChange={setProcessModalOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Process Payout</DialogTitle>
            <DialogDescription>
              Confirm payment details for {selectedPayout?.pandit?.name}
            </DialogDescription>
          </DialogHeader>

          {selectedPayout && (
            <div className="space-y-4 py-4">
              <div className="bg-muted p-4 rounded-md space-y-2 text-sm">
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Booking:</span>
                  <span className="font-medium">{selectedPayout.bookingNumber}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Payout Amount:</span>
                  <span className="font-bold text-lg">₹{selectedPayout.panditPayout}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Bank:</span>
                  <span className="font-medium">State Bank of India</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-muted-foreground">Account:</span>
                  <span className="font-medium">XXXXXXXX4321</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-muted-foreground">IFSC:</span>
                  <span className="font-medium">SBIN0001234</span>
                </div>
              </div>

              <div className="space-y-4">
                <div className="space-y-2">
                  <Label>Payment Method</Label>
                  <Select value={paymentMethod} onValueChange={setPaymentMethod}>
                    <SelectTrigger>
                      <SelectValue />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="BANK_TRANSFER">Bank Transfer (NEFT/IMPS)</SelectItem>
                      <SelectItem value="UPI">UPI</SelectItem>
                      <SelectItem value="CASH">Cash</SelectItem>
                    </SelectContent>
                  </Select>
                </div>
                <div className="space-y-2">
                  <Label>Transaction Reference (UTR / UPI Ref)</Label>
                  <Input
                    value={transactionRef}
                    onChange={e => setTransactionRef(e.target.value)}
                    placeholder="e.g. UTR123456789"
                  />
                </div>
                <div className="space-y-2">
                  <Label>Payment Date</Label>
                  <Input
                    type="date"
                    value={paymentDate}
                    onChange={e => setPaymentDate(e.target.value)}
                  />
                </div>
                <div className="space-y-2">
                  <Label>Admin Notes (optional)</Label>
                  <Textarea
                    value={notes}
                    onChange={e => setNotes(e.target.value)}
                    placeholder="Internal notes about this payout"
                  />
                </div>
              </div>
            </div>
          )}

          <DialogFooter>
            <Button variant="outline" onClick={() => setProcessModalOpen(false)}>Cancel</Button>
            <Button onClick={confirmPayout} disabled={processing}>
              {processing ? "Processing..." : "💰 Confirm Payout"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

"use client";
