        setLoading(true);
        try {
            const token = localStorage.getItem("token");
            const qs = new URLSearchParams();
            if (statusFilter !== "ALL") qs.append("status", statusFilter);
            if (priorityFilter !== "ALL") qs.append("priority", priorityFilter);

            const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001/api/v1'}/admin/support-tickets?${qs.toString()}`, {
                headers: { Authorization: `Bearer ${token}` }
            });
            const json = await res.json();
            if (json.success) {
                setTickets(json.data.data || []);
            }
        } catch (e) {
            console.error(e);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchTickets();
    }, [statusFilter, priorityFilter]);

    const handleLogNewTicket = () => {
        setSource("Phone Call");
        setType("General Inquiry");
        setRelatedBookingId("");
        setRelatedUserId("");
        setSubject("");
        setDescription("");
        setPriority("MEDIUM");
        setStatus("OPEN");
        setLogModalOpen(true);
    };

    const submitTicket = async () => {
        if (!subject || !description) return alert("Subject and Description are required");
        try {
            const token = localStorage.getItem("token");
            const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001/api/v1'}/admin/support-tickets`, {
                method: "POST",
                headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
                body: JSON.stringify({
                    source, type, relatedBookingId, relatedUserId, subject, description, priority, status
                })
            });
            const json = await res.json();
            if (json.success) {
                alert("Ticket logged successfully");
                setLogModalOpen(false);
                fetchTickets();
            } else {
                alert(json.message);
            }
        } catch (e) {
            console.error(e);
            alert("Error logging ticket");
        }
    };

    const handleRowClick = (ticket: any) => {
        setSelectedTicket(ticket);
        setResolution(ticket.resolution || "");
        setUpdateStatus(ticket.status);
        setDetailModalOpen(true);
    };

    const saveTicketUpdate = async () => {
        try {
            const token = localStorage.getItem("token");
            const res = await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001/api/v1'}/admin/support-tickets/${selectedTicket.id}`, {
                method: "PATCH",
                headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
                body: JSON.stringify({ status: updateStatus, resolution })
            });
            const json = await res.json();
            if (json.success) {
                alert("Ticket updated");
                setDetailModalOpen(false);
                fetchTickets();
            } else {
                alert(json.message);
            }
        } catch (e) {
            console.error(e);
        }
    };

    return (
        <div className="p-6 space-y-6 max-w-7xl mx-auto flex-1">
            <div className="flex justify-between items-center">
                <div>
                    <h1 className="text-3xl font-bold tracking-tight">Support Log</h1>
                    <p className="text-muted-foreground mt-1">Manual ticketing for Phone, WhatsApp and Email</p>
                </div>
                <Button onClick={handleLogNewTicket} className="bg-indigo-600 hover:bg-indigo-700">+ Log New Ticket</Button>
            </div>

            <Card>
                <CardHeader className="py-4 bg-muted/30">
                    <div className="flex gap-4 items-center">
                        <div className="flex items-center gap-2">
                            <Label className="text-xs font-bold text-muted-foreground uppercase">Status</Label>
                            <Select value={statusFilter} onValueChange={setStatusFilter}>
                                <SelectTrigger className="w-40 h-8 text-xs">
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="ALL">All Status</SelectItem>
                                    <SelectItem value="OPEN">Open</SelectItem>
                                    <SelectItem value="IN_PROGRESS">In Progress</SelectItem>
                                    <SelectItem value="RESOLVED">Resolved</SelectItem>
                                    <SelectItem value="CLOSED">Closed</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                        <div className="flex items-center gap-2">
                            <Label className="text-xs font-bold text-muted-foreground uppercase">Priority</Label>
                            <Select value={priorityFilter} onValueChange={setPriorityFilter}>
                                <SelectTrigger className="w-40 h-8 text-xs">
                                    <SelectValue />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="ALL">All Priorities</SelectItem>
                                    <SelectItem value="LOW">Low</SelectItem>
                                    <SelectItem value="MEDIUM">Medium</SelectItem>
                                    <SelectItem value="HIGH">High</SelectItem>
                                    <SelectItem value="CRITICAL">Critical</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                    </div>
                </CardHeader>
                <Table>
                    <TableHeader>
                        <TableRow>
                            <TableHead>Date</TableHead>
                            <TableHead>Source</TableHead>
                            <TableHead>Type</TableHead>
                            <TableHead>Subject & Booking</TableHead>
                            <TableHead>Priority</TableHead>
                            <TableHead>Status</TableHead>
                            <TableHead>Actions</TableHead>
                        </TableRow>
                    </TableHeader>
                    <TableBody>
                        {loading ? (
                            <TableRow><TableCell colSpan={7} className="text-center py-10">Loading tickets...</TableCell></TableRow>
                        ) : tickets.length === 0 ? (
                            <TableRow><TableCell colSpan={7} className="text-center py-10">No support tickets found</TableCell></TableRow>
                        ) : (
                            tickets.map(t => (
                                <TableRow key={t.id} className="hover:bg-muted/50 cursor-pointer" onClick={() => handleRowClick(t)}>
                                    <TableCell className="text-xs text-muted-foreground">
                                        {new Date(t.createdAt).toLocaleString()}
                                    </TableCell>
                                    <TableCell className="font-medium text-xs">{t.source}</TableCell>
                                    <TableCell className="text-xs">{t.type}</TableCell>
                                    <TableCell>
                                        <div className="font-medium line-clamp-1">{t.subject}</div>
                                        {t.relatedBookingId && (
                                            <div className="text-xs text-indigo-600">Booking: {t.relatedBookingId}</div>
                                        )}
                                    </TableCell>
                                    <TableCell>
                                        <Badge variant="outline" className={`text-[10px] uppercase ${t.priority === 'CRITICAL' ? 'text-red-700 bg-red-50' : t.priority === 'HIGH' ? 'text-orange-700 bg-orange-50' : ''}`}>
                                            {t.priority}
                                        </Badge>
                                    </TableCell>
                                    <TableCell>
                                        <Badge variant={t.status === 'OPEN' ? 'destructive' : t.status === 'RESOLVED' ? 'default' : t.status === 'CLOSED' ? 'secondary' : 'outline'} className="text-[10px] uppercase">
                                            {t.status}
                                        </Badge>
                                    </TableCell>
                                    <TableCell>
                                        <Button size="sm" variant="ghost" className="text-indigo-600 hover:text-indigo-800 text-xs">Manage →</Button>
                                    </TableCell>
                                </TableRow>
                            ))
                        )}
                    </TableBody>
                </Table>
            </Card>

            <Dialog open={logModalOpen} onOpenChange={setLogModalOpen}>
                <DialogContent className="max-w-2xl">
                    <DialogHeader>
                        <DialogTitle>Log New Support Ticket</DialogTitle>
                        <DialogDescription>Manually log a customer or pandit interaction</DialogDescription>
                    </DialogHeader>

                    <div className="grid grid-cols-2 gap-4 py-4 text-sm">
                        <div className="space-y-2">
                            <Label>Source</Label>
                            <Select value={source} onValueChange={setSource}>
                                <SelectTrigger><SelectValue /></SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="Phone Call">Phone Call</SelectItem>
                                    <SelectItem value="WhatsApp">WhatsApp</SelectItem>
                                    <SelectItem value="Email">Email</SelectItem>
                                    <SelectItem value="In-App">In-App form</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                        <div className="space-y-2">
                            <Label>Type</Label>
                            <Select value={type} onValueChange={setType}>
                                <SelectTrigger><SelectValue /></SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="Booking Issue">Booking Issue</SelectItem>
                                    <SelectItem value="Payment Issue">Payment Issue</SelectItem>
                                    <SelectItem value="Travel Issue">Travel Issue</SelectItem>
                                    <SelectItem value="Pandit Complaint">Pandit Complaint</SelectItem>
                                    <SelectItem value="Customer Complaint">Customer Complaint</SelectItem>
                                    <SelectItem value="General Inquiry">General Inquiry</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                        <div className="space-y-2">
                            <Label>Related Booking ID (optional)</Label>
                            <Input value={relatedBookingId} onChange={e => setRelatedBookingId(e.target.value)} placeholder="e.g. cuidxxxx" />
                        </div>
                        <div className="space-y-2">
                            <Label>Customer/Pandit Phone (optional)</Label>
                            <Input value={relatedUserId} onChange={e => setRelatedUserId(e.target.value)} placeholder="e.g. 9876543210" />
                        </div>
                        <div className="col-span-2 space-y-2">
                            <Label>Subject <span className="text-red-500">*</span></Label>
                            <Input value={subject} onChange={e => setSubject(e.target.value)} placeholder="Brief summary" />
                        </div>
                        <div className="col-span-2 space-y-2">
                            <Label>Description <span className="text-red-500">*</span></Label>
                            <Textarea
                                value={description}
                                onChange={e => setDescription(e.target.value)}
                                placeholder="Full details of the call or message..."
                                className="h-24"
                            />
                        </div>
                        <div className="space-y-2">
                            <Label>Priority</Label>
                            <Select value={priority} onValueChange={setPriority}>
                                <SelectTrigger><SelectValue /></SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="LOW">Low</SelectItem>
                                    <SelectItem value="MEDIUM">Medium</SelectItem>
                                    <SelectItem value="HIGH">High</SelectItem>
                                    <SelectItem value="CRITICAL">Critical</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                        <div className="space-y-2">
                            <Label>Initial Status</Label>
                            <Select value={status} onValueChange={setStatus}>
                                <SelectTrigger><SelectValue /></SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="OPEN">Open</SelectItem>
                                    <SelectItem value="IN_PROGRESS">In Progress</SelectItem>
                                </SelectContent>
                            </Select>
                        </div>
                    </div>

                    <DialogFooter>
                        <Button variant="outline" onClick={() => setLogModalOpen(false)}>Cancel</Button>
                        <Button onClick={submitTicket} className="bg-indigo-600 hover:bg-indigo-700">Submit Ticket</Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

            <Dialog open={detailModalOpen} onOpenChange={setDetailModalOpen}>
                <DialogContent className="max-w-xl">
                    <DialogHeader>
                        <DialogTitle className="flex justify-between items-center pr-4">
                            <span>Manage Ticket</span>
                            <Badge variant={selectedTicket?.priority === 'CRITICAL' ? 'destructive' : 'secondary'} className="uppercase">
                                {selectedTicket?.priority} PRIORITY
                            </Badge>
                        </DialogTitle>
                    </DialogHeader>

                    {selectedTicket && (
                        <div className="space-y-4 py-4 text-sm">
                            <div className="bg-muted p-4 rounded-md space-y-2">
                                <h3 className="font-bold text-lg mb-2">{selectedTicket.subject}</h3>
                                <div className="grid grid-cols-2 gap-2 text-xs">
                                    <span className="text-muted-foreground">Source: <b className="text-foreground">{selectedTicket.source}</b></span>
                                    <span className="text-muted-foreground">Type: <b className="text-foreground">{selectedTicket.type}</b></span>
                                    <span className="text-muted-foreground">Booking: <a href={`/bookings/${selectedTicket.relatedBookingId}`} className="text-indigo-600 underline font-bold">{selectedTicket.relatedBookingId || 'N/A'}</a></span>
                                    <span className="text-muted-foreground">User: <b className="text-foreground">{selectedTicket.relatedUserId || 'N/A'}</b></span>
                                    <span className="text-muted-foreground col-span-2 mt-1">Logged: <b className="text-foreground">{new Date(selectedTicket.createdAt).toLocaleString()}</b></span>
                                </div>
                            </div>

                            <div className="border p-3 rounded-md bg-white">
                                <Label className="text-xs uppercase font-bold text-muted-foreground">Description</Label>
                                <p className="mt-1 whitespace-pre-wrap">{selectedTicket.description}</p>
                            </div>

                            <div className="border-t pt-4 space-y-4">
                                <div className="space-y-2">
                                    <Label>Resolution Notes</Label>
                                    <Textarea
                                        value={resolution}
                                        onChange={e => setResolution(e.target.value)}
                                        placeholder="Add resolution details..."
                                        className="h-20"
                                    />
                                </div>
                                <div className="space-y-2">
                                    <Label>Update Status</Label>
                                    <Select value={updateStatus} onValueChange={setUpdateStatus}>
                                        <SelectTrigger><SelectValue /></SelectTrigger>
                                        <SelectContent>
                                            <SelectItem value="OPEN">Open</SelectItem>
                                            <SelectItem value="IN_PROGRESS">In Progress</SelectItem>
                                            <SelectItem value="RESOLVED">Resolved</SelectItem>
                                            <SelectItem value="CLOSED">Closed</SelectItem>
                                        </SelectContent>
                                    </Select>
                                </div>
                            </div>
                        </div>
                    )}

                    <DialogFooter>
                        <Button variant="outline" onClick={() => setDetailModalOpen(false)}>Close</Button>
                        <Button onClick={saveTicketUpdate} className="bg-indigo-600 hover:bg-indigo-700">Save Updates</Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>

        </div>
    );
}

"use client";
import React, { useEffect, useState } from "react";
import TravelCalculatorModal from "../../components/TravelCalculatorModal";
import { format, differenceInHours } from "date-fns";
import Link from "next/link";

export default function TravelDeskPage() {
    const [activeTab, setActiveTab] = useState("pending");
    const [bookings, setBookings] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);

    const [calculatorModal, setCalculatorModal] = useState<{ isOpen: boolean; bookingId: string | null; bookingData?: any }>({ isOpen: false, bookingId: null });
    const [markBookedModal, setMarkBookedModal] = useState<{ isOpen: boolean; bookingId: string | null; bookingData?: any }>({ isOpen: false, bookingId: null });

    const [bookedForm, setBookedForm] = useState({
        pnr: "", carrier: "", actualCost: "", notes: ""
    });

    const fetchQueue = () => {
        setLoading(true);
        fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001/api/v1'}/admin/travel-queue?tab=${activeTab}`, {
            headers: { Authorization: `Bearer ${localStorage.getItem("adminToken") || ""}` }
        })
            .then(res => res.json())
            .then(data => {
                if (data.success) {
                    setBookings(data.data);
                }
                setLoading(false);
            })
            .catch(() => setLoading(false));
    };

    useEffect(() => {
        fetchQueue();
    }, [activeTab]);

    const handleCalculateSave = async (data: any) => {
        try {
            await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001/api/v1'}/admin/bookings/${calculatorModal.bookingId}/travel-calculate`, {
                method: "PATCH",
                headers: {
                    "Content-Type": "application/json",
                    Authorization: `Bearer ${localStorage.getItem("adminToken") || ""}`
                },
                body: JSON.stringify(data)
            });
            setCalculatorModal({ isOpen: false, bookingId: null });
            fetchQueue();
        } catch (e) {
            console.error(e);
        }
    };

    const handleMarkBooked = async () => {
        try {
            await fetch(`${process.env.NEXT_PUBLIC_API_URL || 'http://localhost:3001/api/v1'}/admin/bookings/${markBookedModal.bookingId}/travel-booked`, {
                method: "PATCH",
                headers: {
                    "Content-Type": "application/json",
                    Authorization: `Bearer ${localStorage.getItem("adminToken") || ""}`
                },
                body: JSON.stringify({
                    travelBookingDetails: { reference: bookedForm.pnr, carrier: bookedForm.carrier, notes: bookedForm.notes },
                    actualTravelCost: parseInt(bookedForm.actualCost) || (markBookedModal.bookingData?.calculatedTravelCost || 0)
                })
            });
            setMarkBookedModal({ isOpen: false, bookingId: null });
            setBookedForm({ pnr: "", carrier: "", actualCost: "", notes: "" });
            fetchQueue();
        } catch (e) {
            console.error(e);
        }
    };

    const copyDetails = (b: any) => {
        const text = `Booking: ${b.bookingNumber}
Pandit: ${b.pandit?.name} (Ph: ${b.pandit?.phone})
From: ${b.pandit?.panditProfile?.location} → To: ${b.venueCity}
Event Date: ${format(new Date(b.eventDate), 'dd MMM yyyy')}
Mode: ${b.travelMode || "Transport"}`;
        navigator.clipboard.writeText(text);
        alert("Copied to clipboard!");
    };

    const tabs = [
        { id: "pending", label: "Needs Travel", icon: "🔴", desc: "Urgent" },
        { id: "calculating", label: "In Progress", icon: "🟡", desc: "Costing" },
        { id: "booked", label: "Booked", icon: "✅", desc: "Done" },
    ];

    return (
        <div className="p-8 max-w-7xl mx-auto space-y-6 flex flex-col h-[calc(100vh-64px)]">

            {/* Header */}
            <div className="flex items-end justify-between shrink-0">
                <div>
                    <h1 className="text-3xl font-black tracking-tight text-slate-800 mb-2">Travel Operations</h1>
                    <p className="text-slate-500 font-medium">Manage and book manual travel arrangements for pandit ji.</p>
                </div>
            </div>

            {/* Tabs */}
            <div className="flex gap-2 p-1 bg-slate-200/50 rounded-xl inline-flex shrink-0">
                {tabs.map(t => (
                    <button
                        key={t.id}
                        onClick={() => setActiveTab(t.id)}
                        className={`px-5 py-2.5 rounded-lg font-bold text-sm transition-all flex items-center gap-2 ${activeTab === t.id
                            ? "bg-white text-slate-900 shadow-sm"
                            : "text-slate-500 hover:text-slate-700 hover:bg-slate-200/50"
                            }`}
                    >
                        <span>{t.icon}</span>
                        {t.label}
                    </button>
                ))}
            </div>

            {/* Queue Area */}
            <div className="flex-1 overflow-y-auto min-h-0 space-y-4 pr-2 pb-10">
                {loading ? (
                    <div className="text-center py-12 text-slate-500 font-medium">Loading queue...</div>
                ) : bookings.length === 0 ? (
                    <div className="bg-white rounded-3xl border border-dashed border-slate-300 p-12 text-center shadow-sm">
                        <span className="material-symbols-outlined text-5xl text-slate-300 mb-4 block">check_circle</span>
                        <h3 className="text-xl font-bold text-slate-700 mb-2">Queue is empty</h3>
                        <p className="text-slate-500">No bookings currently in this stage.</p>
                    </div>
                ) : (
                    bookings.map(b => {
                        const hrsToEvent = differenceInHours(new Date(b.eventDate), new Date());
                        let urgTheme = "bg-white border-slate-200";
                        let urgBadge = null;

                        if (activeTab === "pending" && hrsToEvent < 48) {
                            urgTheme = hrsToEvent < 24 ? "border-red-300 bg-red-50/30 ring-1 ring-red-100" : "border-amber-300 bg-amber-50/30";
                            urgBadge = hrsToEvent < 24 ? (
                                <div className="bg-red-500 text-white text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-t-xl text-center w-full absolute top-0 inset-x-0">🚨 Event in {hrsToEvent} hours!</div>
                            ) : (
                                <div className="bg-amber-500 text-white text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-t-xl text-center w-full absolute top-0 inset-x-0">⚠️ Event Tomorrow</div>
                            );
                        }

                        return (
                            <div key={b.id} className={`relative rounded-2xl border shadow-sm p-6 overflow-hidden transition-shadow hover:shadow-md flex flex-col md:flex-row gap-6 ${urgTheme}`}>
                                {urgBadge}
                                <div className={`flex items-start md:items-center justify-between w-full mt-4 md:mt-0`}>

                                    {/* LEFT */}
                                    <div className="flex-1 min-w-0 pr-6">
                                        <Link href={`/bookings/${b.id}`} className="text-blue-600 font-black text-lg hover:underline decoration-2 underline-offset-4 tracking-tight">
                                            {b.bookingNumber}
                                        </Link>
                                        <p className="text-slate-800 font-bold mt-1.5 flex items-center gap-2">
                                            {b.eventType} <span className="text-slate-300">•</span> {format(new Date(b.eventDate), 'dd MMM yyyy, p')}
                                        </p>

                                        <div className="grid grid-cols-2 gap-4 mt-6">
                                            <div>
                                                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Customer</p>
                                                <p className="text-sm font-bold text-slate-700 truncate">{b.customer?.name}</p>
                                                <p className="text-xs text-slate-500 mt-0.5">{b.venueCity}</p>
                                            </div>
                                            <div>
                                                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1">Pandit</p>
                                                <p className="text-sm font-bold text-slate-700 truncate">{b.pandit?.name}</p>
                                                <p className="text-xs text-slate-500 mt-0.5">{b.pandit?.panditProfile?.location || "Unknown"} <span className="text-blue-500 font-semibold cursor-pointer ml-1">📱 {b.pandit?.phone}</span></p>
                                            </div>
                                        </div>
                                    </div>

                                    {/* MIDDLE */}
                                    <div className="flex-1 min-w-0 px-6 border-l border-r border-slate-100 hidden lg:block h-full">
                                        <div className="text-center mb-6">
                                            <div className="flex items-center justify-center gap-3">
                                                <span className="font-bold text-slate-700">{b.pandit?.panditProfile?.location}</span>
                                                <span className="material-symbols-outlined text-blue-400 text-xl font-light">east</span>
                                                <span className="font-bold text-slate-700">{b.venueCity}</span>
                                            </div>
                                            <p className="text-xs font-semibold text-blue-600 bg-blue-50 px-3 py-1 rounded-full inline-block mt-2">
                                                ~{Math.round(b.travelDistanceKm || 0)} km
                                            </p>
                                        </div>
                                        <div className="bg-slate-50 rounded-xl p-3 text-xs text-slate-600 font-medium space-y-2 border border-slate-100">
                                            <div className="flex justify-between">
                                                <span className="text-slate-400 font-bold">MODE</span>
                                                <span className="font-bold text-slate-800">{b.travelMode || "Transport"}</span>
                                            </div>
                                            <div className="flex justify-between">
                                                <span className="text-slate-400 font-bold">EST. COST</span>
                                                <span className="font-bold text-slate-800">₹{b.calculatedTravelCost || "---"}</span>
                                            </div>
                                        </div>
                                    </div>

                                    {/* RIGHT Actions */}
                                    <div className="w-full md:w-56 flex flex-col gap-3 pl-0 md:pl-6 mt-6 md:mt-0 shrink-0">
                                        {activeTab !== "booked" && (
                                            <button
                                                onClick={() => setCalculatorModal({ isOpen: true, bookingId: b.id, bookingData: b })}
                                                className="w-full bg-white border-2 border-slate-200 hover:border-blue-500 hover:text-blue-700 text-slate-700 font-bold py-2.5 px-4 rounded-xl shadow-sm transition-all focus:ring-4 focus:ring-blue-100 active:scale-95"
                                            >
                                                {b.calculatedTravelCost ? "Edit Calculator" : "🧮 Calculate"}
                                            </button>
                                        )}

                                        <button
                                            onClick={() => copyDetails(b)}
                                            className="w-full bg-slate-100 hover:bg-slate-200 text-slate-600 font-bold py-2 px-4 rounded-xl text-sm transition-colors"
                                        >
                                            📋 Copy Details
                                        </button>

                                        {activeTab !== "booked" && (
                                            <button
                                                onClick={() => {
                                                    setBookedForm({ ...bookedForm, actualCost: String(b.calculatedTravelCost || "") });
                                                    setMarkBookedModal({ isOpen: true, bookingId: b.id, bookingData: b });
                                                }}
                                                className="w-full bg-green-500 hover:bg-green-600 text-white font-black py-3 px-4 rounded-xl shadow-md shadow-green-500/20 transition-all active:scale-95 mt-2 flex items-center justify-center gap-2 group"
                                            >
                                                ✅ Mark Booked
                                                <span className="material-symbols-outlined text-sm opacity-50 group-hover:opacity-100 group-hover:translate-x-1 transition-all">arrow_forward</span>
                                            </button>
                                        )}

                                        {activeTab === "booked" && (
                                            <div className="bg-green-50 border border-green-200 p-3 rounded-xl text-center">
                                                <p className="text-xs font-black text-green-600 uppercase tracking-wider mb-1">Actual Cost</p>
                                                <p className="text-2xl tracking-tight font-black text-green-700">₹{b.travelCost}</p>
                                            </div>
                                        )}
                                    </div>
                                </div>
                            </div>
                        );
                    })
                )}
            </div>

            {/* Modals */}
            {calculatorModal.isOpen && (
                <TravelCalculatorModal
                    booking={calculatorModal.bookingData}
                    onClose={() => setCalculatorModal({ isOpen: false, bookingId: null })}
                    onSave={handleCalculateSave}
                />
            )}

            {markBookedModal.isOpen && (
                <div className="fixed inset-0 bg-slate-900/50 backdrop-blur-sm z-50 flex items-center justify-center p-4 overflow-y-auto">
                    <div className="bg-white rounded-3xl w-full max-w-sm shadow-2xl p-6 relative">
                        <h2 className="text-xl font-bold text-slate-900 mb-6 flex items-center gap-2">
